  "request_id": "rf-suggest-edit-compressor-parameter-placeholder-ordering-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕选中的压缩机 compressor-3 的缺失参数问题生成候选提案，重点是补齐出口压力控制目标、防喘振审查所需的最小流量旁路百分比，以及当前审查基线所需的效率百分比占位。",
      "issues": [
        {
          "title": "压缩机出口压力控制目标缺失",
          "details": "compressor-3 已配置为 outlet_pressure 控制，但当前缺少对应的出口压力目标参数。",
          "citations": [
            "diag-1",
            "flowdoc-unit-1",
            "snapshot-1"
          ]
        },
        {
          "title": "防喘振审查所需最小流量旁路百分比缺失",
          "details": "compressor-3 标记为需要 anti-surge review，但缺少 minimum flow bypass percent 参数。",
          "citations": [
            "diag-2",
            "flowdoc-unit-1",
            "snapshot-1"
          ]
        },
        {
          "title": "效率百分比基线输入缺失",
          "details": "compressor-3 缺少当前审查基线所需的 efficiency percent 输入。",
          "citations": [
            "diag-3",
            "flowdoc-unit-1",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 compressor-3 增加出口压力目标占位参数",
          "target": {
            "type": "unit",
            "id": "compressor-3"
          },
          "rationale": "直接对应 outlet pressure 控制目标缺失诊断。使用占位参数而非自动赋值，可在不擅自改变求解设定的前提下，为审查者提供最小可确认补丁入口。",
          "patch": {
            "parameter_placeholders": [
              {
                "path": "config.outlet_pressure_target_kpa",
                "expected_type": "number",
                "reason": "required_by_control_mode_outlet_pressure"
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-unit-1",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 compressor-3 增加最小流量旁路百分比占位参数",
          "target": {
            "type": "unit",
            "id": "compressor-3"
          },
          "rationale": "直接对应防喘振审查所需参数缺失诊断。该提案仅增加局部参数占位，避免在缺少审查依据时推断具体百分比。",
          "patch": {
            "parameter_placeholders": [
              {
                "path": "config.minimum_flow_bypass_percent",
                "expected_type": "number",
                "units": "percent",
                "reason": "required_by_anti_surge_review"
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-unit-1",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 compressor-3 增加效率百分比占位参数",
          "target": {
            "type": "unit",
            "id": "compressor-3"
          },
          "rationale": "直接对应效率基线输入缺失诊断。当前证据只支持补充占位，不支持推断效率数值。",
          "patch": {
            "parameter_placeholders": [
              {
                "path": "config.efficiency_percent",
                "expected_type": "number",
                "units": "percent",
                "reason": "required_by_review_baseline"
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-3",
